import{_ as n,o as a,c as t,ag as l}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Klanten","description":"","frontmatter":{},"headers":[],"relativePath":"nl/features/customers.md","filePath":"nl/features/customers.md"}'),r={name:"nl/features/customers.md"};function i(o,e,s,d,g,k){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="klanten" tabindex="-1">Klanten <a class="header-anchor" href="#klanten" aria-label="Permalink to &quot;Klanten&quot;">‚Äã</a></h1><p>Beheer je volledige klantendatabase. Elke factuur, offerte en elk project is gekoppeld aan een klantrecord.</p><h2 id="overzicht" tabindex="-1">Overzicht <a class="header-anchor" href="#overzicht" aria-label="Permalink to &quot;Overzicht&quot;">‚Äã</a></h2><p>De klantenpagina toont al je klanten met belangrijke informatie in een oogopslag. Gebruik zoek- en filterfuncties om snel klanten te vinden.</p><h2 id="een-klant-aanmaken" tabindex="-1">Een klant aanmaken <a class="header-anchor" href="#een-klant-aanmaken" aria-label="Permalink to &quot;Een klant aanmaken&quot;">‚Äã</a></h2><ol><li>Ga naar <strong>Klanten &gt; Nieuwe klant</strong></li><li>Vul de klantgegevens in: <ul><li><strong>Naam</strong> ‚Äî Bedrijfs- of persoonsnaam (verplicht)</li><li><strong>E-mail</strong> ‚Äî Contacte-mail voor het versturen van facturen</li><li><strong>Telefoon</strong> ‚Äî Contacttelefoonnummer</li><li><strong>Adres</strong> ‚Äî Straat, postcode, plaats, land</li><li><strong>BTW-nummer</strong> ‚Äî BTW-registratie van de klant (voor B2B)</li><li><strong>Klantnummer</strong> ‚Äî Automatisch gegenereerd of aangepast</li></ul></li><li>Klik op <strong>Opslaan</strong></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Je kunt ook klanten inline aanmaken bij het maken van een factuur of offerte ‚Äî je hoeft niet weg te navigeren.</p></div><h2 id="klantdetailpagina" tabindex="-1">Klantdetailpagina <a class="header-anchor" href="#klantdetailpagina" aria-label="Permalink to &quot;Klantdetailpagina&quot;">‚Äã</a></h2><p>De klantdetailpagina toont:</p><ul><li><strong>Contactgegevens</strong> ‚Äî Alle opgeslagen gegevens</li><li><strong>Factuurgeschiedenis</strong> ‚Äî Elke factuur die naar deze klant is gestuurd</li><li><strong>Uitgavengeschiedenis</strong> ‚Äî Uitgaven gekoppeld aan deze klant</li><li><strong>Projecten</strong> ‚Äî Actieve en voltooide projecten</li><li><strong>Statistieken</strong> ‚Äî Totale omzet, openstaand saldo, gemiddelde betaaltijd</li></ul><h2 id="acties" tabindex="-1">Acties <a class="header-anchor" href="#acties" aria-label="Permalink to &quot;Acties&quot;">‚Äã</a></h2><ul><li><strong>Bewerken</strong> ‚Äî Klantinformatie bijwerken</li><li><strong>Factuur aanmaken</strong> ‚Äî Start een nieuwe factuur vooraf ingevuld met deze klant</li><li><strong>Offerte aanmaken</strong> ‚Äî Start een nieuwe offerte voor deze klant</li><li><strong>Archiveren</strong> ‚Äî Verplaats naar archief (kan later worden hersteld)</li><li><strong>Verwijderen</strong> ‚Äî Verwijder de klant permanent</li></ul><h2 id="bulkacties" tabindex="-1">Bulkacties <a class="header-anchor" href="#bulkacties" aria-label="Permalink to &quot;Bulkacties&quot;">‚Äã</a></h2><p>Selecteer meerdere klanten voor:</p><ul><li><strong>Archiveren</strong> ‚Äî Inactieve klanten in bulk archiveren</li><li><strong>Herstellen</strong> ‚Äî Gearchiveerde klanten terughalen</li><li><strong>Verwijderen</strong> ‚Äî Meerdere klanten verwijderen</li></ul><h2 id="snelle-weergave" tabindex="-1">Snelle weergave <a class="header-anchor" href="#snelle-weergave" aria-label="Permalink to &quot;Snelle weergave&quot;">‚Äã</a></h2><p>Op desktop kun je op een klant in de lijst klikken om het <strong>snelle weergave</strong> schuifpaneel te openen. Dit toont belangrijke details en acties zonder de lijst te verlaten:</p><ul><li>Samenvatting klantinfo</li><li>Recente facturen</li><li>Bewerkknop om de volledige bewerkpagina te openen</li></ul><h2 id="klanten-importeren" tabindex="-1">Klanten importeren <a class="header-anchor" href="#klanten-importeren" aria-label="Permalink to &quot;Klanten importeren&quot;">‚Äã</a></h2><p>Importeer je bestaande klantendatabase vanuit CSV:</p><ol><li>Ga naar <strong>Profiel &gt; Importeren</strong></li><li>Selecteer <strong>Klanten</strong> als gegevenstype</li><li>Upload je CSV-bestand</li><li>Koppel je CSV-kolommen aan MyCompanyDesk-velden (naam, e-mail, adres, etc.)</li><li>Bekijk het voorbeeld</li><li>Bevestig om te importeren</li></ol><h2 id="klanten-exporteren" tabindex="-1">Klanten exporteren <a class="header-anchor" href="#klanten-exporteren" aria-label="Permalink to &quot;Klanten exporteren&quot;">‚Äã</a></h2><p>Exporteer je klantenlijst als CSV vanaf de klantenpagina (Pro-abonnement en hoger).</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">‚Äã</a></h2><ul><li>Houd e-mailadressen van klanten up-to-date ‚Äî ze worden gebruikt voor factuurverzending</li><li>Gebruik de zoekbalk voor directe fuzzy-matching over alle klantvelden</li><li>Pin je belangrijkste klanten als favorieten voor snelle toegang</li><li>Vul BTW-nummers in om verlegde BTW op B2B-facturen in te schakelen</li></ul>',25)])])}const p=n(r,[["render",i]]);export{u as __pageData,p as default};
